mapper.select:
/* 데이터셋 목록 조회 dataset.selectDatasetList */ SELECT D.DATASET_ID, D.DS_NM, D.DESCRIPTION, D.VERSION, D.DATASET_BUILD_STATUS_CD, D.USE_YN, DATE_FORMAT(D.MODIFY_DT, '%Y-%m-%d') AS MODIFY_DT, D.CHUNK_CNT, D.SRCH_QUAL, D.CHUNK_SIZE, D.CHUNK_OVERLAP, D.MIN_CHUNK_SZ,
COALESCE(DOC_CNT.DOC_CNT, 0) AS DOC_CNT, COALESCE(URL_CNT.URL_CNT, 0) AS URL_CNT,
EM.CODE_NM AS EMBED_MODEL_NM, VDB.CODE_NM AS VECTOR_DB_NM, CA.CODE_NM AS CHUNK_ALGO_NM, HI.CODE_NM AS HDR_INCL_NM
FROM TB_DS D
LEFT JOIN ( SELECT DATASET_ID, COUNT(*) AS DOC_CNT FROM TB_DS_DOC GROUP BY DATASET_ID ) DOC_CNT ON D.DATASET_ID = DOC_CNT.DATASET_ID
LEFT JOIN ( SELECT DATASET_ID, COUNT(*) AS URL_CNT FROM TB_DS_URL GROUP BY DATASET_ID ) URL_CNT ON D.DATASET_ID = URL_CNT.DATASET_ID
/* 임베딩 모델 코드 */ LEFT JOIN TB_CODE EM ON EM.CODE_GRP_ID = 'RG000004' AND EM.CODE_ID = D.EMBED_MODEL_CD
/* 벡터DB 코드 */ LEFT JOIN TB_CODE VDB ON VDB.CODE_GRP_ID = 'RG000005' AND VDB.CODE_ID = D.VECTOR_DB_CD
/* 청크 알고리즘 코드 */ LEFT JOIN TB_CODE CA ON CA.CODE_GRP_ID = 'RG000002' AND CA.CODE_ID = D.CHUNK_ALGO_CD
/* 헤더 포함 여부 코드 */ LEFT JOIN TB_CODE HI ON HI.CODE_GRP_ID = 'RG000003' AND HI.CODE_ID = D.HDR_INCL_CD
ORDER BY D.CREATE_DT DESC

mapper.insert:
/* 데이터셋 등록/수정 dataset.saveDataset */
INSERT INTO TB_DS (
    DATASET_ID
    , DS_NM
    , DESCRIPTION
    , VERSION
    , CHUNK_ALGO_CD
    , CHUNK_SIZE
    , CHUNK_OVERLAP
    , MIN_CHUNK_SZ
    , HDR_INCL_CD
    , DATASET_BUILD_STATUS_CD
    , EMBED_MODEL_CD
    , VECTOR_DB_CD
    , EMBED_NORM_CD
    , POOL_STRAT_CD
    , DIM_REDUC_CD
    , CHUNK_CNT
    , SRCH_QUAL
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{datasetId}
    , #{dsNm, jdbcType=VARCHAR}
    , #{description, jdbcType=VARCHAR}
    , #{version, jdbcType=VARCHAR}
    , #{chunkAlgoCd, jdbcType=VARCHAR}
    , #{chunkSize, jdbcType=INTEGER}
    , #{chunkOverlap, jdbcType=INTEGER}
    , #{minChunkSz, jdbcType=INTEGER}
    , #{hdrInclCd, jdbcType=VARCHAR}
    , #{datasetBuildStatusCd, jdbcType=VARCHAR}
    , #{embedModelCd, jdbcType=VARCHAR}
    , #{vectorDbCd, jdbcType=VARCHAR}
    , #{embedNormCd, jdbcType=VARCHAR}
    , #{poolStratCd, jdbcType=VARCHAR}
    , #{dimReducCd, jdbcType=VARCHAR}
    , #{chunkCnt, jdbcType=INTEGER}
    , #{srchQual, jdbcType=DECIMAL}
    , #{useYn, jdbcType=VARCHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    DS_NM = VALUES(DS_NM)
    , DESCRIPTION = VALUES(DESCRIPTION)
    , VERSION = VALUES(VERSION)
    , CHUNK_ALGO_CD = VALUES(CHUNK_ALGO_CD)
    , CHUNK_SIZE = VALUES(CHUNK_SIZE)
    , CHUNK_OVERLAP = VALUES(CHUNK_OVERLAP)
    , MIN_CHUNK_SZ = VALUES(MIN_CHUNK_SZ)
    , HDR_INCL_CD = VALUES(HDR_INCL_CD)
    , DATASET_BUILD_STATUS_CD = VALUES(DATASET_BUILD_STATUS_CD)
    , EMBED_MODEL_CD = VALUES(EMBED_MODEL_CD)
    , VECTOR_DB_CD = VALUES(VECTOR_DB_CD)
    , EMBED_NORM_CD = VALUES(EMBED_NORM_CD)
    , POOL_STRAT_CD = VALUES(POOL_STRAT_CD)
    , DIM_REDUC_CD = VALUES(DIM_REDUC_CD)
    , CHUNK_CNT = VALUES(CHUNK_CNT)
    , SRCH_QUAL = VALUES(SRCH_QUAL)
    , USE_YN = VALUES(USE_YN)
    , MODIFY_DT = NOW()

/* 데이터셋 전처리 등록/수정 dataset.saveDatasetPreproc */
INSERT INTO TB_DS_PREPROC (
    DATASET_ID
    , LOWERCASE_YN
    , WSP_NORM_YN
    , SPEC_CHR_RM_YN
    , SINGLE_CELL_TEXT
    , SENT_SPLIT_ALGO_CD
    , LANG_DETECT_CD
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{datasetId}
    , #{lowercaseYn, jdbcType=VARCHAR}
    , #{wspNormYn, jdbcType=VARCHAR}
    , #{specChrRmYn, jdbcType=VARCHAR}
    , #{singleCellText, jdbcType=VARCHAR}
    , #{sentSplitAlgoCd, jdbcType=VARCHAR}
    , #{langDetectCd, jdbcType=VARCHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
    LOWERCASE_YN = VALUES(LOWERCASE_YN)
    , WSP_NORM_YN = VALUES(WSP_NORM_YN)
    , SPEC_CHR_RM_YN = VALUES(SPEC_CHR_RM_YN)
    , SINGLE_CELL_TEXT = VALUES(SINGLE_CELL_TEXT)
    , SENT_SPLIT_ALGO_CD = VALUES(SENT_SPLIT_ALGO_CD)
    , LANG_DETECT_CD = VALUES(LANG_DETECT_CD)
    , MODIFY_DT = NOW()

mapper.delete:
/* 데이터셋 삭제 dataset.deleteDataset */
DELETE FROM TB_DS
WHERE DATASET_ID = #{datasetId}

/* 데이터셋 전처리 삭제 dataset.deleteDatasetPreproc */
DELETE FROM TB_DS_PREPROC
WHERE DATASET_ID = #{datasetId}

/* 데이터셋 문서 삭제 dataset.deleteDatasetDoc */
DELETE FROM TB_DS_DOC
WHERE DATASET_ID = #{datasetId}

/* 데이터셋 URL 삭제 dataset.deleteDatasetUrl */
DELETE FROM TB_DS_URL
WHERE DATASET_ID = #{datasetId}

